import java.math.BigDecimal;

import com.rosetta.model.lib.records.Date;
import com.rosetta.model.metafields.FieldWithMetaDate;
import com.rosetta.model.metafields.FieldWithMetaString;

import cdm.base.staticdata.asset.common.Asset;
import cdm.base.staticdata.asset.common.AssetIdentifier;
import cdm.base.staticdata.asset.common.AssetIdTypeEnum;
import cdm.base.staticdata.asset.common.Cash;
import cdm.base.staticdata.identifier.AssignedIdentifier;
import cdm.base.staticdata.party.Counterparty;
import cdm.base.staticdata.party.CounterpartyRoleEnum;
import cdm.base.staticdata.party.Party;
import cdm.base.staticdata.party.PartyIdentifier;
import cdm.base.staticdata.party.PartyRole;
import cdm.base.staticdata.party.PartyRoleEnum;
import cdm.base.staticdata.party.PayerReceiver;
import cdm.base.staticdata.party.metafields.ReferenceWithMetaParty;

import cdm.event.common.Trade;
import cdm.event.common.TradeIdentifier;

import cdm.observable.asset.metafields.ReferenceWithMetaObservable;
import cdm.observable.asset.Observable;
import cdm.observable.asset.PriceQuantity;
import cdm.observable.asset.PriceSchedule;
import cdm.observable.asset.PriceTypeEnum;
import cdm.observable.asset.metafields.FieldWithMetaPriceSchedule;

import cdm.base.math.UnitType;
import cdm.base.math.NonNegativeQuantitySchedule;
import cdm.base.math.metafields.FieldWithMetaNonNegativeQuantitySchedule;

import cdm.product.common.settlement.SettlementDate;
import cdm.product.common.settlement.SettlementTerms;
import cdm.product.common.settlement.SettlementTypeEnum;

import cdm.product.template.EconomicTerms;
import cdm.product.template.NonTransferableProduct;
import cdm.product.template.Payout;
import cdm.product.template.SettlementPayout;
import cdm.product.template.TradeLot;
import cdm.product.template.Underlier;

public class CdmTradeBuilder {

    public static Trade buildTrade() {
        // tradeDate: 2001-11-12 - use FieldWithMetaDate with Date
        FieldWithMetaDate tradeDate = FieldWithMetaDate.builder()
            .setValue(Date.of(2001, 11, 12))
            .build();

        // TradeIdentifier[0]: FWD123 with issuer party1
        AssignedIdentifier assignedId1 = AssignedIdentifier.builder()
            .setIdentifier(FieldWithMetaString.builder().setValue("FWD123").build())
            .build();

        TradeIdentifier tradeIdentifier1 = TradeIdentifier.builder()
            .addAssignedIdentifier(assignedId1)
            .setIssuer(FieldWithMetaString.builder().setValue("party1").build())
            .build();

        // TradeIdentifier[1]: FXD2002987 with issuer party1
        AssignedIdentifier assignedId2 = AssignedIdentifier.builder()
            .setIdentifier(FieldWithMetaString.builder().setValue("FXD2002987").build())
            .build();

        TradeIdentifier tradeIdentifier2 = TradeIdentifier.builder()
            .addAssignedIdentifier(assignedId2)
            .setIssuer(FieldWithMetaString.builder().setValue("party1").build())
            .build();

        // Party[0]: party1 / CITIUS33
        Party party1 = Party.builder()
            .addPartyId(PartyIdentifier.builder()
                .setIdentifier(FieldWithMetaString.builder().setValue("party1").build())
                .build())
            .setName(FieldWithMetaString.builder().setValue("CITIUS33").build())
            .build();

        // Party[1]: party2 / UBSWCHZH
        Party party2 = Party.builder()
            .addPartyId(PartyIdentifier.builder()
                .setIdentifier(FieldWithMetaString.builder().setValue("party2").build())
                .build())
            .setName(FieldWithMetaString.builder().setValue("UBSWCHZH").build())
            .build();

        // Counterparty[0]: Party1
        Counterparty counterparty1 = Counterparty.builder()
            .setRole(CounterpartyRoleEnum.PARTY_1)
            .setPartyReference(ReferenceWithMetaParty.builder()
                .setGlobalReference("party1")
                .build())
            .build();

        // Counterparty[1]: Party2
        Counterparty counterparty2 = Counterparty.builder()
            .setRole(CounterpartyRoleEnum.PARTY_2)
            .setPartyReference(ReferenceWithMetaParty.builder()
                .setGlobalReference("party2")
                .build())
            .build();

        // PartyRole[0]: Buyer (party1)
        PartyRole partyRole1 = PartyRole.builder()
            .setRole(PartyRoleEnum.BUYER)
            .setPartyReference(ReferenceWithMetaParty.builder()
                .setGlobalReference("party1")
                .build())
            .build();

        // PartyRole[1]: Seller (party2)
        PartyRole partyRole2 = PartyRole.builder()
            .setRole(PartyRoleEnum.SELLER)
            .setPartyReference(ReferenceWithMetaParty.builder()
                .setGlobalReference("party2")
                .build())
            .build();

        // Underlier: Observable -> Asset -> Cash (GBP currency)
        AssetIdentifier assetId = AssetIdentifier.builder()
            .setIdentifier(FieldWithMetaString.builder().setValue("GBP").build())
            .setIdentifierType(AssetIdTypeEnum.CURRENCY_CODE)
            .build();

        Cash cash = Cash.builder()
            .addIdentifier(assetId)
            .build();

        Asset asset = Asset.builder()
            .setCash(cash)
            .build();

        Observable observable = Observable.builder()
            .setAsset(asset)
            .build();

        Underlier underlier = Underlier.builder()
            .setObservable(ReferenceWithMetaObservable.builder()
                .setValue(observable)
                .build())
            .build();

        // SettlementPayout
        PayerReceiver payerReceiver = PayerReceiver.builder()
            .setPayer(CounterpartyRoleEnum.PARTY_1)
            .setReceiver(CounterpartyRoleEnum.PARTY_2)
            .build();

        // SettlementDate: 2002-04-01 - use Date
        SettlementDate settlementDate = SettlementDate.builder()
            .setValueDate(Date.of(2002, 4, 1))
            .build();

        SettlementTerms settlementTerms = SettlementTerms.builder()
            .setSettlementDate(settlementDate)
            .setSettlementType(SettlementTypeEnum.PHYSICAL)
            .build();

        SettlementPayout settlementPayout = SettlementPayout.builder()
            .setPayerReceiver(payerReceiver)
            .setSettlementTerms(settlementTerms)
            .setUnderlier(underlier)
            .build();

        Payout payout = Payout.builder()
            .setSettlementPayout(settlementPayout)
            .build();

        EconomicTerms economicTerms = EconomicTerms.builder()
            .addPayout(payout)
            .build();

        NonTransferableProduct product = NonTransferableProduct.builder()
            .setEconomicTerms(economicTerms)
            .build();

        // Price: 1.4643 USD/GBP, ExchangeRate type
        UnitType priceUnit = UnitType.builder()
            .setCurrency(FieldWithMetaString.builder().setValue("USD").build())
            .build();

        UnitType pricePerUnit = UnitType.builder()
            .setCurrency(FieldWithMetaString.builder().setValue("GBP").build())
            .build();

        PriceSchedule priceSchedule = PriceSchedule.builder()
            .setValue(BigDecimal.valueOf(1.4643))
            .setUnit(priceUnit)
            .setPerUnitOf(pricePerUnit)
            .setPriceType(PriceTypeEnum.EXCHANGE_RATE)
            .build();

        // Quantity[0]: 10,000,000 GBP
        UnitType quantity1Unit = UnitType.builder()
            .setCurrency(FieldWithMetaString.builder().setValue("GBP").build())
            .build();

        NonNegativeQuantitySchedule quantity1 = NonNegativeQuantitySchedule.builder()
            .setValue(BigDecimal.valueOf(10000000.0))
            .setUnit(quantity1Unit)
            .build();

        // Quantity[1]: 14,643,000 USD
        UnitType quantity2Unit = UnitType.builder()
            .setCurrency(FieldWithMetaString.builder().setValue("USD").build())
            .build();

        NonNegativeQuantitySchedule quantity2 = NonNegativeQuantitySchedule.builder()
            .setValue(BigDecimal.valueOf(14643000.0))
            .setUnit(quantity2Unit)
            .build();

        PriceQuantity priceQuantity = PriceQuantity.builder()
            .addPrice(FieldWithMetaPriceSchedule.builder().setValue(priceSchedule).build())
            .addQuantity(FieldWithMetaNonNegativeQuantitySchedule.builder().setValue(quantity1).build())
            .addQuantity(FieldWithMetaNonNegativeQuantitySchedule.builder().setValue(quantity2).build())
            .build();

        TradeLot tradeLot = TradeLot.builder()
            .addPriceQuantity(priceQuantity)
            .build();

        // Build the Trade
        Trade trade = Trade.builder()
            .setTradeDate(tradeDate)
            .addTradeIdentifier(tradeIdentifier1)
            .addTradeIdentifier(tradeIdentifier2)
            .addParty(party1)
            .addParty(party2)
            .addCounterparty(counterparty1)
            .addCounterparty(counterparty2)
            .addPartyRole(partyRole1)
            .addPartyRole(partyRole2)
            .setProduct(product)
            .addTradeLot(tradeLot)
            .build();

        return trade;
    }

    public static void main(String[] args) throws Exception {
        Trade trade = buildTrade();

        com.fasterxml.jackson.databind.ObjectMapper mapper =
            com.regnosys.rosetta.common.serialisation.RosettaObjectMapper
                .getNewRosettaObjectMapper();

        String tradeJson = mapper.writerWithDefaultPrettyPrinter()
            .writeValueAsString(trade);

        // Wrap in {"trade": ...} to match input format
        System.out.println("{\"trade\":" + tradeJson + "}");
    }
}
